// ─── Min-Heap in JavaScript ─────────────────────────────────────────────────

class MinHeap {
  constructor() { this.heap = []; }

  // Index helpers
  #parent(i)    { return Math.floor((i - 1) / 2); }
  #left(i)      { return 2 * i + 1; }
  #right(i)     { return 2 * i + 2; }
  #swap(i, j)   { [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]]; }

  // O(1) — peek minimum
  peek()    { return this.heap[0]; }
  size()    { return this.heap.length; }
  isEmpty() { return this.heap.length === 0; }

  // O(log n) — insert
  insert(value) {
    this.heap.push(value);
    this.#bubbleUp(this.heap.length - 1);
  }

  #bubbleUp(i) {
    while (i > 0) {
      const p = this.#parent(i);
      if (this.heap[p] <= this.heap[i]) break;
      this.#swap(i, p);
      i = p;
    }
  }

  // O(log n) — extract minimum
  extractMin() {
    if (this.isEmpty()) return null;
    const min = this.heap[0];
    const last = this.heap.pop();
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.#siftDown(0);
    }
    return min;
  }

  #siftDown(i) {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const l = this.#left(i), r = this.#right(i);
      if (l < n && this.heap[l] < this.heap[smallest]) smallest = l;
      if (r < n && this.heap[r] < this.heap[smallest]) smallest = r;
      if (smallest === i) break;
      this.#swap(i, smallest);
      i = smallest;
    }
  }

  // O(n) — build heap from array
  static heapify(arr) {
    const h = new MinHeap();
    h.heap = [...arr];
    // Sift-down all internal nodes bottom-up
    for (let i = Math.floor(h.heap.length / 2) - 1; i >= 0; i--)
      h.#siftDown(i);
    return h;
  }

  // O(log n) — delete at arbitrary index
  deleteAt(index) {
    const last = this.heap.pop();
    if (index === this.heap.length) return; // deleted the last element
    const old = this.heap[index];
    this.heap[index] = last;
    if (last < old) this.#bubbleUp(index);
    else            this.#siftDown(index);
  }

  // O(log n) — update key
  updateKey(index, newValue) {
    const old = this.heap[index];
    this.heap[index] = newValue;
    if (newValue < old) this.#bubbleUp(index);
    else                this.#siftDown(index);
  }
}

// Usage
const h = MinHeap.heapify([5, 3, 8, 1, 9, 2, 7]);
console.log(h.peek());       // 1
console.log(h.extractMin()); // 1
console.log(h.peek());       // 2
h.insert(0);
console.log(h.peek());       // 0

// ─── Heap in Java ────────────────────────────────────────────────────────────
//
// java.util.PriorityQueue is a min-heap by default.
// Use Collections.reverseOrder() or a custom Comparator for max-heap.

import java.util.*;

public class HeapExamples {
    public static void main(String[] args) {

        // ── Min-heap via PriorityQueue ────────────────────────────────────
        PriorityQueue<Integer> minHeap = new PriorityQueue<>();
        minHeap.offer(5);             // O(log n)
        minHeap.offer(1);
        minHeap.offer(3);

        System.out.println(minHeap.peek());  // O(1) → 1
        System.out.println(minHeap.poll());  // O(log n) → 1

        // ── Max-heap ─────────────────────────────────────────────────────
        PriorityQueue<Integer> maxHeap =
            new PriorityQueue<>(Collections.reverseOrder());
        maxHeap.offer(5); maxHeap.offer(9); maxHeap.offer(3);
        System.out.println(maxHeap.peek());  // → 9

        // ── Heapify from collection — O(n) ────────────────────────────────
        List<Integer> list = Arrays.asList(5, 3, 8, 1, 9, 2, 7);
        PriorityQueue<Integer> pq = new PriorityQueue<>(list); // O(n)
        System.out.println(pq.peek()); // → 1

        // ── Custom object with priority ───────────────────────────────────
        PriorityQueue<int[]> tasks =
            new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        tasks.offer(new int[]{2, 0}); // [priority, id]
        tasks.offer(new int[]{1, 1});
        tasks.offer(new int[]{3, 2});
        int[] top = tasks.poll();     // → [1, 1] — highest priority
    }

    // ── Manual min-heap implementation ───────────────────────────────────
    static class MinHeap {
        private int[] heap;
        private int size;

        MinHeap(int capacity) { heap = new int[capacity]; }

        int parent(int i) { return (i - 1) / 2; }
        int left(int i)   { return 2 * i + 1; }
        int right(int i)  { return 2 * i + 2; }

        void swap(int i, int j) { int t = heap[i]; heap[i] = heap[j]; heap[j] = t; }

        void insert(int v) {
            heap[size] = v;
            int i = size++;
            while (i > 0 && heap[parent(i)] > heap[i]) {
                swap(i, parent(i));
                i = parent(i);
            }
        }

        int extractMin() {
            int min = heap[0];
            heap[0] = heap[--size];
            siftDown(0);
            return min;
        }

        void siftDown(int i) {
            int smallest = i;
            int l = left(i), r = right(i);
            if (l < size && heap[l] < heap[smallest]) smallest = l;
            if (r < size && heap[r] < heap[smallest]) smallest = r;
            if (smallest != i) { swap(i, smallest); siftDown(smallest); }
        }

        int peek() { return heap[0]; }
    }
}

// ─── Heap in C++ ─────────────────────────────────────────────────────────────
//
// std::priority_queue is a max-heap by default.
// Use std::greater<T> for min-heap.
// std::make_heap, push_heap, pop_heap operate on any random-access range.

#include <queue>
#include <vector>
#include <algorithm>
#include <functional>

int main() {
    // ── Max-heap (default) ────────────────────────────────────────────────
    std::priority_queue<int> maxPQ;
    maxPQ.push(5);            // O(log n)
    maxPQ.push(1);
    maxPQ.push(9);
    int top = maxPQ.top();    // O(1) → 9
    maxPQ.pop();              // O(log n)

    // ── Min-heap ─────────────────────────────────────────────────────────
    std::priority_queue<int,
        std::vector<int>,
        std::greater<int>> minPQ;
    minPQ.push(5); minPQ.push(1); minPQ.push(9);
    int minTop = minPQ.top(); // → 1

    // ── Heapify from vector — O(n) ─────────────────────────────────────
    std::vector<int> v = {5, 3, 8, 1, 9, 2, 7};
    std::make_heap(v.begin(), v.end());          // max-heap, O(n)
    // v[0] is the max (9)

    std::push_heap(v.begin(), v.end());          // O(log n)
    std::pop_heap(v.begin(), v.end());           // O(log n) — moves max to back
    v.pop_back();                                // remove it

    // ── Min-heap on vector ────────────────────────────────────────────────
    std::make_heap(v.begin(), v.end(), std::greater<int>());

    // ── Custom comparator — sort by priority field ────────────────────
    using Task = std::pair<int,std::string>; // {priority, name}
    std::priority_queue<Task,
        std::vector<Task>,
        std::greater<Task>> taskQ;
    taskQ.push({2, "medium"});
    taskQ.push({1, "urgent"});
    auto [pri, name] = taskQ.top(); // → {1, "urgent"}

    return 0;
}
